CREATE TABLE metric_domains
(
	id serial,
	code character varying (64) NOT NULL,
	name character varying (128) DEFAULT NULL,
	description character varying (255) DEFAULT NULL,
	CONSTRAINT pk_metric_domains PRIMARY KEY (id)
);
CREATE INDEX i_metric_domains_code ON metric_domains (code);
CREATE INDEX i_metric_domains_name ON metric_domains (name);
